 353	function selectTower(type) {
 354	    selectedTowerType = type;
 355	    selectedTower = null;
 356	    hideTowerInfo();
 357	    uiButtons.forEach(btn => {
 358	        const isSelected = btn.getData('towerType') === type;
 359	        btn.setFillStyle(isSelected ? 0xffffff : TOWER_TYPES[btn.getData('towerType')].color);
 360	        btn.setScale(isSelected ? 1.1 : 1);
 361	    });
 362	}
 363	
 364	function selectExistingTower(x, y) {
 365	    let found = null;
 366	    towers.getChildren().forEach(t => {
 367	        if (Phaser.Math.Distance.Between(x, y, t.x, t.y) < 25) {
 368	            found = t;
 369	        }
 370	    });
 371	    
 372	    if (found) {
 373	        selectedTower = found;
 374	        selectedTowerType = null;
 375	        uiButtons.forEach(btn => btn.setFillStyle(TOWER_TYPES[btn.getData('towerType')].color).setScale(1));
 376	        showTowerInfo(found);
 377	    } else {
 378	        selectedTower = null;
 379	        hideTowerInfo();
 380	    }
 381	}
