212	                (child.getData && child.getData('id') === params.nodeId)) {
213	                target = child;
214	            }
215	        });
216	
217	        if (!target) {
218	            throw new Error('Object not found: ' + params.nodeId);
219	        }
220	
221	        // 设置属性（支持嵌套路径如 body.velocity.x）
222	        const parts = params.property.split('.');
223	        let obj = target;
224	        for (let i = 0; i < parts.length - 1; i++) {
225	            obj = obj[parts[i]];
226	            if (!obj) throw new Error('Property path not found: ' + params.property);
227	        }
228	        obj[parts[parts.length - 1]] = params.value;
229	
230	        return { set: true, nodeId: params.nodeId, property: params.property, value: params.value };
231	    }
232	
233	    function reloadGame() {
234	        window.location.reload();
235	        return { reloading: true };
236	    }
237	
238	    // 拦截 console 日志
239	    const consoleLogs = [];
240	    const originalConsoleLog = console.log;
241	    const originalConsoleWarn = console.warn;
242	    const originalConsoleError = console.error;
243	    const originalConsoleInfo = console.info;
244	
245	    function interceptConsole(original, level) {
246	        return function() {
247	            const args = Array.prototype.slice.call(arguments);
248	            consoleLogs.push({
249	                level: level,
250	                message: args.map(a => typeof a === 'object' ? JSON.stringify(a) : String(a)).join(' '),
251	                timestamp: Date.now()
252	            });
253	            // 保留最多 500 条
254	            if (consoleLogs.length > 500) consoleLogs.shift();
255	            original.apply(console, args);
256	        };
257	    }
258	
259	    console.log = interceptConsole(originalConsoleLog, 'log');
260	    console.warn = interceptConsole(originalConsoleWarn, 'warn');
261	    console.error = interceptConsole(originalConsoleError, 'error');
262	    console.info = interceptConsole(originalConsoleInfo, 'info');
263	
264	    function getConsoleLogs(params) {
265	        const level = params && params.level ? params.level : 'all';
266	        const limit = params && params.limit ? params.limit : 50;
267	        const since = params && params.since ? params.since : 0;
268	
269	        let filtered = consoleLogs;
270	        if (level !== 'all') {
271	            filtered = filtered.filter(log => log.level === level);
272	        }
273	        if (since > 0) {
274	            filtered = filtered.filter(log => log.timestamp > since);
275	        }
276	
277	        return filtered.slice(-limit);
278	    }
279	
280	    function getPerformance(params) {
281	        const gameObj = window.game;
282	        if (!gameObj) throw new Error('Phaser game not found');
283	
284	        const perf = {
285	            fps: gameObj.loop.actualFps || 0,
286	            targetFps: gameObj.loop.targetFps || 60,
287	            delta: gameObj.loop.delta || 0,
288	            time: gameObj.loop.time || 0,
289	            isRunning: gameObj.loop.isRunning
290	        };
291	
292	        // 内存信息（如果可用）
293	        if (performance && performance.memory) {
294	            perf.memory = {
295	                usedJSHeapSize: performance.memory.usedJSHeapSize,
296	                totalJSHeapSize: performance.memory.totalJSHeapSize,
297	                jsHeapSizeLimit: performance.memory.jsHeapSizeLimit
298	            };
299	        }
300	
301	        // Canvas 信息
302	        const canvas = document.querySelector('canvas');
303	        if (canvas) {
304	            perf.canvas = {
305	                width: canvas.width,
306	                height: canvas.height,
307	                renderer: gameObj.renderer ? gameObj.renderer.type : 'unknown'
308	            };
309	        }
310	
311	        return perf;
312	    }
313	
314	    // 网络请求拦截
315	    const networkLogs = [];
316	    const originalFetch = window.fetch;
317	    const originalXHROpen = XMLHttpRequest.prototype.open;
318	    const originalXHRSend = XMLHttpRequest.prototype.send;
319	
320	    window.fetch = function() {
321	        const url = arguments[0];
322	        const startTime = Date.now();
323	        return originalFetch.apply(window, arguments).then(function(response) {
324	            networkLogs.push({
325	                method: 'fetch',
326	                url: url,
327	                status: response.status,
328	                timestamp: startTime,
329	                duration: Date.now() - startTime
330	            });
331	            return response;
332	        }).catch(function(err) {
333	            networkLogs.push({
334	                method: 'fetch',
335	                url: url,
336	                error: err.message,
337	                timestamp: startTime,
338	                duration: Date.now() - startTime
339	            });
340	            throw err;
341	        });
342	    };
343	
344	    XMLHttpRequest.prototype.open = function(method, url) {
345	        this._xhrMethod = method;
346	        this._xhrUrl = url;
347	        this._xhrStartTime = Date.now();
348	        return originalXHROpen.apply(this, arguments);
349	    };
350	
351	    XMLHttpRequest.prototype.send = function() {
352	        const xhr = this;
353	        xhr.addEventListener('load', function() {
354	            networkLogs.push({
355	                method: 'xhr',
356	                url: xhr._xhrUrl,
357	                status: xhr.status,
358	                timestamp: xhr._xhrStartTime,
359	                duration: Date.now() - xhr._xhrStartTime
360	            });
361	        });
362	        return originalXHRSend.apply(this, arguments);
363	    };
364	
365	    function getNetworkLogs(params) {
366	        const limit = params && params.limit ? params.limit : 50;
367	        const since = params && params.since ? params.since : 0;
368	
369	        let filtered = networkLogs;
370	        if (since > 0) {
371	            filtered = filtered.filter(log => log.timestamp > since);
372	        }
373	
374	        return filtered.slice(-limit);
375	    }
376	
377	    function evaluateJS(params) {
378	        if (!params || !params.expression) {
379	            throw new Error('Missing expression');
380	        }
381	        const result = eval(params.expression);
382	        return {
383	            result: typeof result === 'object' ? JSON.stringify(result) : String(result),
384	            type: typeof result
385	        };
386	    }
387	
388	    function simulateClick(params) {
389	        let target;
390	        if (params && params.selector) {
391	            target = document.querySelector(params.selector);
392	        } else if (params && params.x !== undefined && params.y !== undefined) {
393	            target = document.elementFromPoint(params.x, params.y);
394	        } else {
395	            throw new Error('Missing selector or x/y coordinates');
396	        }
397	
398	        if (!target) throw new Error('Element not found');
399	
400	        const rect = target.getBoundingClientRect();
401	        const clickEvent = new MouseEvent('click', {
402	            bubbles: true,
403	            cancelable: true,
404	            clientX: rect.left + rect.width / 2,
405	            clientY: rect.top + rect.height / 2
406	        });
407	        target.dispatchEvent(clickEvent);
408	
409	        return { clicked: true, tag: target.tagName, text: (target.textContent || '').substring(0, 50) };
410	    }
411	
412	    function simulateInputText(params) {
413	        if (!params || !params.selector || params.value === undefined) {
414	            throw new Error('Missing selector or value');
415	        }
416	        const target = document.querySelector(params.selector);
417	        if (!target) throw new Error('Element not found: ' + params.selector);
418	
419	        target.value = params.value;
420	        target.dispatchEvent(new Event('input', { bubbles: true }));
421	        target.dispatchEvent(new Event('change', { bubbles: true }));
422	
423	        return { input: true, value: params.value };
424	    }
425	
426	    function simulateKeyPress(params) {
427	        if (!params || !params.key) {
428	            throw new Error('Missing key');
429	        }
430	
431	        let target = document;
432	        if (params.selector) {
433	            target = document.querySelector(params.selector);
434	            if (!target) target = document;
435	        }
436	
437	        const keyEvent = new KeyboardEvent('keydown', {
438	            key: params.key,
439	            code: params.code || params.key,
440	            keyCode: params.keyCode || 0,
441	            bubbles: true
442	        });
443	        target.dispatchEvent(keyEvent);
444	
445	        const keyUpEvent = new KeyboardEvent('keyup', {
446	            key: params.key,
447	            code: params.code || params.key,
448	            keyCode: params.keyCode || 0,
449	            bubbles: true
450	        });
451	        target.dispatchEvent(keyUpEvent);
452	
453	        return { pressed: true, key: params.key };
454	    }
455	
456	    function simulateDrag(params) {
457	        if (!params || params.fromX === undefined || params.fromY === undefined ||
458	            params.toX === undefined || params.toY === undefined) {
459	            throw new Error('Missing fromX/fromY/toX/toY');
460	        }
461	
462	        const canvas = document.querySelector('canvas');
463	        if (!canvas) throw new Error('Canvas not found');
464	
465	        const duration = params.duration || 300;
466	
467	        // mousedown
468	        canvas.dispatchEvent(new MouseEvent('mousedown', {
469	            bubbles: true, cancelable: true,
470	            clientX: params.fromX, clientY: params.fromY
471	        }));
472	
473	        // mousemove
474	        canvas.dispatchEvent(new MouseEvent('mousemove', {
475	            bubbles: true, cancelable: true,
476	            clientX: params.toX, clientY: params.toY
477	        }));
478	
479	        // mouseup
480	        canvas.dispatchEvent(new MouseEvent('mouseup', {
481	            bubbles: true, cancelable: true,
482	            clientX: params.toX, clientY: params.toY
483	        }));
484	
485	        return { dragged: true, from: { x: params.fromX, y: params.fromY }, to: { x: params.toX, y: params.toY } };
486	    }
487	
488	    function getElementInfo(params) {
489	        let target;
490	        if (params && params.selector) {
491	            target = document.querySelector(params.selector);
492	        } else if (params && params.x !== undefined && params.y !== undefined) {
493	            target = document.elementFromPoint(params.x, params.y);
494	        } else {
495	            throw new Error('Missing selector or x/y coordinates');
496	        }
497	
498	        if (!target) throw new Error('Element not found');
499	
500	        const rect = target.getBoundingClientRect();
501	        const info = {
502	            tag: target.tagName.toLowerCase(),
503	            id: target.id || null,
504	            className: target.className || null,
505	            text: (target.textContent || '').substring(0, 200),
506	            x: Math.round(rect.x),
507	            y: Math.round(rect.y),
508	            width: Math.round(rect.width),
509	            height: Math.round(rect.height),
510	            visible: rect.width > 0 && rect.height > 0
511	        };
512	
513	        // 获取常用属性
514	        const attrs = {};
515	        for (let i = 0; i < target.attributes.length; i++) {
516	            const attr = target.attributes[i];
517	            attrs[attr.name] = attr.value;
518	        }
519	        info.attributes = attrs;
520	
521	        return info;
522	    }
523	
524	    console.log('[sandbox-bridge] Bridge loaded and ready');
525	})();

