  1	/**
  2	 * AHIVE Core - 统一错误处理
  3	 * 
  4	 * 功能：
  5	 * - 统一错误码定义
  6	 * - 错误处理中间件
  7	 * - 错误日志记录
  8	 */
  9	
 10	import type { IncomingMessage, ServerResponse } from 'http';
 11	import { logger } from './index.js';
 12	
 13	// ============ 错误码定义 ============
 14	
 15	export enum ErrorCode {
 16	  // 通用错误 (1000-1999)
 17	  UNKNOWN_ERROR = 1000,
 18	  INVALID_REQUEST = 1001,
 19	  INVALID_PARAMS = 1002,
 20	  NOT_FOUND = 1003,
 21	  UNAUTHORIZED = 1004,
 22	  FORBIDDEN = 1005,
 23	  
 24	  // 智能体错误 (2000-2999)
 25	  AGENT_NOT_FOUND = 2000,
 26	  AGENT_ALREADY_EXISTS = 2001,
 27	  AGENT_CREATION_FAILED = 2002,
 28	  AGENT_EXECUTION_FAILED = 2003,
 29	  AGENT_TIMEOUT = 2004,
 30	  
 31	  // 会话错误 (3000-3999)
 32	  SESSION_NOT_FOUND = 3000,
 33	  SESSION_EXPIRED = 3001,
 34	  SESSION_CREATION_FAILED = 3002,
 35	  
 36	  // 模型错误 (4000-4999)
 37	  MODEL_NOT_FOUND = 4000,
 38	  MODEL_LOAD_FAILED = 4001,
 39	  MODEL_INFERENCE_FAILED = 4002,
 40	  PROVIDER_NOT_AVAILABLE = 4003,
 41	  
 42	  // 工具错误 (5000-5999)
 43	  TOOL_NOT_FOUND = 5000,
 44	  TOOL_EXECUTION_FAILED = 5001,
 45	  TOOL_TIMEOUT = 5002,
 46	  INVALID_TOOL_PARAMS = 5003,
 47	  
 48	  // 文件错误 (6000-6999)
 49	  FILE_NOT_FOUND = 6000,
 50	  FILE_READ_ERROR = 6001,
 51	  FILE_WRITE_ERROR = 6002,
 52	  FILE_DELETE_ERROR = 6003,
 53	  FILE_TOO_LARGE = 6004,
 54	  
 55	  // 网络错误 (7000-7999)
 56	  NETWORK_ERROR = 7000,
 57	  REQUEST_TIMEOUT = 7001,
 58	  CONNECTION_REFUSED = 7002,
 59	  
 60	  // 内存错误 (8000-8999)
 61	  MEMORY_ERROR = 8000,
 62	  MEMORY_OVERFLOW = 8001,
 63	  CONTEXT_TOO_LONG = 8002,
 64	}
 65	
 66	// ============ 错误类 ============
 67	
 68	export class AppError extends Error {
 69	  constructor(
 70	    public code: ErrorCode,
 71	    message: string,
 72	    public statusCode: number = 500,
 73	    public details?: any
 74	  ) {
 75	    super(message);
 76	    this.name = 'AppError';
 77	  }
 78	
 79	  toJSON() {
 80	    return {
 81	      error: this.message,
 82	      code: this.code,
 83	      statusCode: this.statusCode,
 84	      details: this.details,
 85	    };
 86	  }
 87	}
 88	
 89	// ============ 错误工厂 ============
 90	
 91	export class ErrorFactory {
 92	  static notFound(resource: string): AppError {
 93	    return new AppError(
 94	      ErrorCode.NOT_FOUND,
 95	      `${resource} not found`,
 96	      404
 97	    );
 98	  }
 99	
100	  static invalidParams(message: string, details?: any): AppError {
101	    return new AppError(
102	      ErrorCode.INVALID_PARAMS,
103	      message,
104	      400,
105	      details
106	    );
107	  }
108	
109	  static unauthorized(message: string = 'Unauthorized'): AppError {
110	    return new AppError(
111	      ErrorCode.UNAUTHORIZED,
112	      message,
113	      401
114	    );
115	  }
116	
117	  static forbidden(message: string = 'Forbidden'): AppError {
118	    return new AppError(
119	      ErrorCode.FORBIDDEN,
120	      message,
121	      403
122	    );
123	  }
124	
125	  static agentNotFound(agentId: string): AppError {
126	    return new AppError(
127	      ErrorCode.AGENT_NOT_FOUND,
128	      `Agent ${agentId} not found`,
129	      404
130	    );
131	  }
132	
133	  static sessionNotFound(sessionId: string): AppError {
134	    return new AppError(
135	      ErrorCode.SESSION_NOT_FOUND,
136	      `Session ${sessionId} not found`,
137	      404
138	    );
139	  }
140	
141	  static modelNotFound(modelId: string): AppError {
142	    return new AppError(
143	      ErrorCode.MODEL_NOT_FOUND,
144	      `Model ${modelId} not found`,
145	      404
146	    );
147	  }
148	
149	  static toolExecutionFailed(toolName: string, error: Error): AppError {
150	    return new AppError(
151	      ErrorCode.TOOL_EXECUTION_FAILED,
152	      `Tool ${toolName} execution failed: ${error.message}`,
153	      500,
154	      { toolName, error: error.message }
155	    );
156	  }
157	
158	  static fileTooLarge(size: number, maxSize: number): AppError {
159	    return new AppError(
160	      ErrorCode.FILE_TOO_LARGE,
161	      `File size ${size} exceeds maximum ${maxSize}`,
162	      413,
163	      { size, maxSize }
164	    );
165	  }
166	
167	  static contextTooLong(length: number, maxLength: number): AppError {
168	    return new AppError(
169	      ErrorCode.CONTEXT_TOO_LONG,
170	      `Context length ${length} exceeds maximum ${maxLength}`,
171	      400,
172	      { length, maxLength }
173	    );
174	  }
175	}
176	
177	// ============ 错误处理中间件 ============
178	
179	export async function handleError(
180	  error: Error | AppError,
181	  req: IncomingMessage,
182	  res: ServerResponse
183	): Promise<void> {
184	  // 记录错误日志
185	  logger.error('[ErrorHandler]', {
186	    url: req.url,
187	    method: req.method,
188	    error: error.message,
189	    stack: error.stack,
190	  });
191	
192	  // 设置响应头
193	  res.setHeader('Content-Type', 'application/json; charset=utf-8');
194	
195	  // 根据错误类型返回不同的响应
196	  if (error instanceof AppError) {
197	    res.writeHead(error.statusCode);
198	    res.end(JSON.stringify(error.toJSON()));
199	  } else {
200	    // 未知错误
201	    res.writeHead(500);
202	    res.end(JSON.stringify({
203	      error: 'Internal Server Error',
204	      code: ErrorCode.UNKNOWN_ERROR,
205	      message: error.message,
206	    }));
207	  }
208	}
209	
210	// ============ 错误处理包装器 ============
211	
212	export function withErrorHandler(
213	  handler: (req: IncomingMessage, res: ServerResponse) => Promise<void>
214	): (req: IncomingMessage, res: ServerResponse) => Promise<void> {
215	  return async (req: IncomingMessage, res: ServerResponse) => {
216	    try {
217	      await handler(req, res);
218	    } catch (error) {
219	      await handleError(error as Error, req, res);
220	    }
221	  };
222	}
223	
224	// ============ 异步错误处理包装器 ============
225	
226	export function asyncHandler(
227	  fn: (req: IncomingMessage, res: ServerResponse) => Promise<void>
228	): (req: IncomingMessage, res: ServerResponse) => void {
229	  return (req: IncomingMessage, res: ServerResponse) => {
230	    Promise.resolve(fn(req, res)).catch((error) => {
231	      handleError(error, req, res);
232	    });
233	  };
234	}

