 430	  /**
 431	   * 计算两个字符串的相似度（基于实际内容）
 432	   */
 433	  private calculateSimilarity(str1: string, str2: string): number {
 434	    const content1 = this.extractActualContent(str1);
 435	    const content2 = this.extractActualContent(str2);
 436	
 437	    if (!content1 || !content2) return 0;
 438	    if (content1 === content2) return 1;
 439	
 440	    const len1 = content1.length;
 441	    const len2 = content2.length;
 442	    const maxLen = Math.max(len1, len2);
 443	
 444	    if (maxLen === 0) return 1;
 445	
 446	    // 计算编辑距离
 447	    const dp: number[][] = Array(len1 + 1).fill(null).map(() => Array(len2 + 1).fill(0));
 448	    for (let i = 0; i <= len1; i++) dp[i][0] = i;
 449	    for (let j = 0; j <= len2; j++) dp[0][j] = j;
 450	
 451	    for (let i = 1; i <= len1; i++) {
 452	      for (let j = 1; j <= len2; j++) {
 453	        if (content1[i - 1] === content2[j - 1]) {
 454	          dp[i][j] = dp[i - 1][j - 1];
 455	        } else {
 456	          dp[i][j] = Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]) + 1;
 457	        }
 458	      }
 459	    }
 460	
 461	    const distance = dp[len1][len2];
 462	    return 1 - distance / maxLen;
 463	  }
