206	function truncateContent(content: string | MultiModalContent[], maxLen: number, suffix: string = ''): string | MultiModalContent[] {
207	  if (typeof content === 'string') {
208	    return content.length > maxLen ? content.slice(0, maxLen) + suffix : content;
209	  }
210	  // 多模态内容只截断文本部分
211	  const text = getContentAsText(content);
212	  if (text.length <= maxLen) return content;
213	  return [{ type: 'text', text: text.slice(0, maxLen) + suffix }];
214	}
215	
216	/** 按轮次分组消息 */
217	function groupMessagesByTurn(messages: InternalMessage[]): Map<string, InternalMessage[]> {
218	  const turns = new Map<string, InternalMessage[]>();
219	  for (const msg of messages) {
220	    if (!msg.turnId) {
221	      // 系统消息没有 turnId，单独处理
222	      const systemTurn = turns.get('system') || [];
223	      systemTurn.push(msg);
224	      turns.set('system', systemTurn);
225	    } else {
226	      const turnMessages = turns.get(msg.turnId) || [];
227	      turnMessages.push(msg);
228	      turns.set(msg.turnId, turnMessages);
229	    }
230	  }
231	  return turns;
232	}
233	
234	/** 获取最近N轮对话（排除系统消息轮次） */
235	function getRecentTurns(messages: InternalMessage[], n: number): InternalMessage[] {
236	  const turns = groupMessagesByTurn(messages);
237	  const turnIds = Array.from(turns.keys()).filter(id => id !== 'system');
238	  const recentTurnIds = turnIds.slice(-n);
239	
240	  // 返回系统消息 + 最近N轮
241	  const result: InternalMessage[] = [];
242	  const systemMessages = turns.get('system') || [];
243	  result.push(...systemMessages);
244	
245	  for (const id of recentTurnIds) {
246	    result.push(...(turns.get(id) || []));
247	  }
248	
249	  return result;
250	}
