599	  private checkTaskCompletion(responseContent: string, hasToolCalls: boolean): {
600	    isComplete: boolean;
601	    reason?: string;
602	    isWaitingForUser?: boolean;
603	  } {
604	    // 有工具调用 → 任务未完成
605	    if (hasToolCalls) {
606	      this.taskCompletionState.consecutiveNoToolCalls = 0;
607	      this.taskCompletionState.detectedComplete = false;
608	      return { isComplete: false };
609	    }
610	
611	    // 更新状态（保留 lastResponseContent 用于信号词检测）
612	    this.taskCompletionState.lastResponseContent = responseContent;
613	
614	    // 🆕 优先检测"等待用户输入"信号词（智能体在等待用户反馈，应该暂停）
615	    // 参考 CODEX: 用户意图检测 - 等待用户输入时不应继续执行
616	    const waitingForUserSignals = [
617	      '等待审核',
618	      '等待确认',
619	      '等待批准',
620	      '等待用户',
621	      '等待您的',
622	      '请确认',
623	      '请审核',
624	      '请审批',
625	      '请选择',
626	      '请决定',
627	      '需要您确认',
628	      '需要您审核',
629	      '需要您批准',
630	      '需要您选择',
631	      '等待您的确认',
632	      '等待您的审核',
633	      '等待您的批准',
634	      '等待您的选择',
635	      // 🔧 Issue 6 修复：英文信号词收窄为强意图表达，移除了容易误判的 'wait for', 'waiting for', 'please review', 'awaiting'
636	      'please confirm before proceeding',
637	      'awaiting your approval',
638	      'awaiting your confirmation',
639	    ];
640	
641	    const hasWaitingSignal = waitingForUserSignals.some(signal =>
642	      responseContent.toLowerCase().includes(signal.toLowerCase())
643	    );
644	
645	    // 🔧 关键修复：检测到"等待用户"信号时，暂停执行，等待用户输入
646	    if (hasWaitingSignal) {
647	      log.info(`检测到等待用户信号，暂停执行等待用户输入`);
648	      return {
649	        isComplete: true,
650	        reason: '智能体等待用户确认/审核，暂停执行',
651	        isWaitingForUser: true,
652	      };
653	    }
654	
655	    // 检测真正的完成信号词（任务真正完成，不需要用户输入）
656	    // 注意：不包含"等待审核"等信号词
657	    // 使用更严格的正则匹配，避免 "the file is complete" 等误判
658	    const completionPatterns = [
659	      /任务[已经]?完成/,
660	      /工作[已经]?完成/,
661	      /问题[已经]?解决/,
662	      /已成功完成/,
663	      /已完成任务/,
664	      /task (is )?complete/i,
665	      /task (is )?done/i,
666	      /all tasks? (are )?done/i,
667	      /work (is )?complete/i,
668	      /mission accomplished/i,
669	    ];
670	
671	    const hasCompletionSignal = completionPatterns.some(p => p.test(responseContent));
672	
673	    if (hasCompletionSignal) {
674	      this.taskCompletionState.detectedComplete = true;
