690	  async execute(llmService: AhiveCoderLLMService, options: AhiveCoderExecuteOptions): Promise<{
691	    content: string;
692	    iterations: number;
693	    toolCallsExecuted: number;
694	  }> {
695	    const { systemPrompt, userMessage, sessionMessages, modelConfig, onEvent, agentId, memorySystem, memorySpace } = options;
696	
697	    // 记忆空间：默认 'ahive-coder'，CORE 智能体使用 'core'
698	    const space = memorySpace || 'ahive-coder';
699	
700	    // 🔍 调试日志：检查memorySystem和agentId
701	    log.info(`[AhiveCoderExecutor] execute调用: agentId=${agentId}, memorySystem=${memorySystem ? '存在' : '不存在'}, memorySpace=${space}`);
702	
703	    // 🔧 新增：存储记忆系统引用，用于运行时压缩持久化
704	    this.memorySystem = memorySystem;
705	    this.agentId = agentId || null;
706	    this.memorySpace = space;
707	
708	    this.onEvent = onEvent;
709	    this.currentTurnId = `turn_${randomUUID().slice(0, 8)}`;
710	    this.abortController = new AbortController();
711	    this.compactedThisTurn = false;  // E-7: 重置压缩标志
712	    this.toolCallHistory.clear();    // 🔧 重置工具调用统计（每 turn 重新统计）
713	
714	    // 构建消息列表：冷启动从文件读，热续从内存复用
715	    if (!this.historyInitialized || this.conversationHistory.length === 0) {
716	      // 冷启动：首次execute()或clearHistory()后，从持久化加载
717	      this.conversationHistory = [
718	        createSystemMessage(systemPrompt),
719	      ];
720	
721	      // 加载历史记忆上下文（双重来源）
722	      if (memorySystem && agentId) {
723	        try {
724	          // 1. 从 SQLite 加载压缩摘要（历史上下文）
725	          const memoryContext = await memorySystem.getMemoryContext(agentId, space, 4000);
726	          if (memoryContext) {
727	            this.conversationHistory.push(createSystemMessage(memoryContext));
728	            log.info(`加载了历史压缩摘要 (space: ${space})`);
729	          }
730	
731	          // 2. 从 rollout 文件加载最近对话（当前会话上下文）
732	          const recentItems = await memorySystem.getRecentRolloutItems(agentId, space, 100);
733	          if (recentItems && recentItems.length > 0) {
734	            const historyText = this.formatMemoryAsHistory(recentItems, this.config.historyTokenBudget);
735	            if (historyText) {
736	              this.conversationHistory.push(createSystemMessage(`## 最近对话\n\n${historyText}`));
737	              log.info(`加载了 ${recentItems.length} 条最近对话 (space: ${space}, 预算: ${this.config.historyTokenBudget} tokens)`);
738	            }
739	          }
740	        } catch (error) {
741	          log.warn('加载记忆失败:', error);
742	        }
743	      }
744	      this.historyInitialized = true;
745	      log.info(`[AhiveCoderExecutor] 冷启动: 从持久化加载 ${this.conversationHistory.length} 条消息`);
746	    } else {
747	      // 热续：复用内存中已有的history，只更新systemPrompt
748	      this.conversationHistory[0] = createSystemMessage(systemPrompt);
749	      log.info(`[AhiveCoderExecutor] 热续: 复用内存中 ${this.conversationHistory.length} 条消息`);
750	    }
